const cfg = $input.first().json;
const queries = cfg.searchQueries.split(',').map(q => q.trim()).filter(Boolean);
// 2 pages per query: start=0 and start=25 → 50 jobs per keyword
return queries.flatMap((q, i) => [
  { json: { ...cfg, currentQuery: q, queryIndex: i * 2,     pageStart: 0  } },
  { json: { ...cfg, currentQuery: q, queryIndex: i * 2 + 1, pageStart: 25 } }
]);

// Parse LinkedIn Guest API HTML response into structured job data
// LinkedIn returns HTML <li> elements, one per job card
const items = $input.all();
const jobs = [];

for (const item of items) {
  // The response body is a string of HTML
  const html = typeof item.json === 'string' ? item.json : (item.json.data || item.json.body || '');
  if (!html || html.length < 50) continue;

  // Split into individual job card blocks by list item
  const blocks = html.split(/<\/li>/);

  for (const block of blocks) {
    try {
      // Extract LinkedIn job ID from data-entity-urn or data-job-id
      const jobIdMatch = block.match(/data-entity-urn="urn:li:jobPosting:(\d+)"/) ||
                         block.match(/data-job-id="(\d+)"/) ||
                         block.match(/\/jobs\/view\/(\d+)/);
      if (!jobIdMatch) continue;
      const jobId = jobIdMatch[1];

      // Extract job title
      const titleMatch = block.match(/base-search-card__title[^>]*>\s*([^<]+)\s*</) ||
                         block.match(/<h3[^>]*>\s*([^<]+)\s*<\/h3>/);

      // Extract company name  
      const companyMatch = block.match(/base-search-card__subtitle[^>]*>[\s\S]*?<[^>]+>\s*([^<]+)\s*<\//) ||
                           block.match(/base-search-card__subtitle[^>]*>\s*([^<]+)\s*</);

      // Extract location
      const locationMatch = block.match(/job-search-card__location[^>]*>\s*([^<]+)\s*</) ||
                            block.match(/base-search-card__metadata[^>]*>\s*([^<]+)\s*</);

      // Extract job URL
      const urlMatch = block.match(/href="(https:\/\/[\w.]*linkedin\.com\/jobs\/view\/[^"?]+)/);

      // Extract posted date
      const dateMatch = block.match(/datetime="([\d-]+T?[\d:Z.-]*)"/);

      // Check for Easy Apply indicator
      const isEasyApply = /easy.apply/i.test(block) || /data-easy-apply/i.test(block);

      // Check for remote
      const isRemote = /\bremote\b/i.test(block) || /\bhome.?office\b/i.test(block);

      const company = companyMatch ? companyMatch[1].trim().replace(/\s+/g, ' ') : 'Unknown';
      const position = titleMatch ? titleMatch[1].trim().replace(/\s+/g, ' ') : 'Unknown';

      if (company === 'Unknown' && position === 'Unknown') continue;

      jobs.push({
        job_id: `li_${jobId}`,
        company,
        position,
        location: locationMatch ? locationMatch[1].trim().replace(/\s+/g, ' ') : 'Unknown',
        job_url: urlMatch ? urlMatch[1] : `https://www.linkedin.com/jobs/view/${jobId}/`,
        apply_type: isEasyApply ? 'LinkedIn Easy Apply' : 'LinkedIn External',
        is_linkedin: 'Yes',
        is_remote: isRemote ? 'Yes' : 'No',
        employment_type: 'FULLTIME',
        posted_date: dateMatch ? dateMatch[1].split('T')[0] : new Date().toISOString().split('T')[0],
        description: '',
        status: 'Not Applied',
        priority: 'Medium',
        applied_date: '',
        cover_letter_generated: 'No',
        resume_optimized: 'No',
        missing_skills: '',
        application_id: '',
        notes: '',
        last_checked: new Date().toISOString().split('T')[0]
      });
    } catch(e) {
      // Skip malformed block
    }
  }
}

console.log(`Parsed ${jobs.length} jobs from LinkedIn`);
return jobs.length > 0 ? jobs.map(j => ({ json: j })) : [{ json: { job_id: '', hasNewJobs: false, _empty: true } }];

const incomingJobs = $('📋 Parse LinkedIn HTML → Job Data').all();
const sheetRows = $('📊 Get Existing Job IDs').all();

// ── READ FROM CONFIG (change values in ⚙️ Config node, not here) ──────────
const cfg = $('⚙️ Config').first().json;

const ENGLISH_ONLY = cfg.englishOnly !== 'false' && cfg.englishOnly !== false;
const PM_KEYWORDS   = String(cfg.pmKeywords || '')
  .split(',').map(k => k.trim().toLowerCase()).filter(Boolean);

// ── LANGUAGE FILTER ───────────────────────────────────────────────────────
function isEnglishJob(title) {
  if (!ENGLISH_ONLY) return true;           // skip filter if disabled in Config
  const t = (title || '').toLowerCase();

  // Block German gender notation — only "w" variants (weiblich), NOT (m/f/d)
  if (/\([mwfd]*w[mwfd]*\/[mwfd]+\/[dxm]\)/i.test(t)) return false;
  if (/\([mwfd]+\/[mwfd]*w[mwfd]*\/[dxm]\)/i.test(t)) return false;

  // German female-form suffixes: /in, *in
  if (/\/in[\s),]|\/in$|\*in/i.test(t)) return false;

  // German-specific characters (ä ö ü ß)
  if (/[äöüß]/i.test(title || '')) return false;

  // German words in job titles
  const germanWords = [
    ' für ', ' und ', ' mit ', ' bei ', ' als ', ' von ', ' zur ', ' zum ',
    ' der ', ' die ', ' das ', ' im ', ' zu ',
    'entwickler', 'leiter', 'berater', 'mitarbeiter', 'teamleiter',
    'projektleiter', 'sachbearbeiter', 'kaufmann', 'kauffrau',
    'fachkraft', 'stellenangebot', 'gesucht', 'vollzeit', 'teilzeit',
    'festanstellung', 'unbefristet', 'befristet', 'ausbildung',
    'praktikum', 'werkstudent', 'referent', 'fachinformatiker'
  ];
  if (germanWords.some(w => t.includes(w))) return false;

  return true;
}

// ── ROLE RELEVANCE FILTER ────────────────────────────────────────────────
function isPmRole(title) {
  if (PM_KEYWORDS.length === 0) return true;  // skip if no keywords set
  const t = (title || '').toLowerCase();
  return PM_KEYWORDS.some(kw => t.includes(kw));
}

// ── PIPELINE ─────────────────────────────────────────────────────────────

// Step 1: within-run deduplication (same job from multiple queries/pages)
const seenInRun = new Set();
const deduped = incomingJobs.filter(item => {
  const jobId = String(item.json.job_id || '').trim();
  if (!jobId || seenInRun.has(jobId)) return false;
  seenInRun.add(jobId);
  return true;
});

// Step 2: language filter
const englishJobs = deduped.filter(item =>
  isEnglishJob(item.json.position || item.json.title || '')
);

// Step 3: role relevance filter (from Config → pmKeywords)
let nonPmCount = 0;
const pmJobs = englishJobs.filter(item => {
  const title = item.json.position || item.json.title || '';
  if (!isPmRole(title)) { nonPmCount++; return false; }
  return true;
});

// Step 4: exclude jobs already in the sheet
const existingIds = new Set(
  sheetRows.map(item => {
    const id = item.json.job_id || item.json.Job_ID || item.json['job id'] || '';
    return String(id).trim();
  }).filter(id => id.length > 3)
);

console.log(`Raw:${incomingJobs.length} → deduped:${deduped.length} → EN:${englishJobs.length} → PM:${pmJobs.length} (+${nonPmCount} non-PM skipped) → sheet:${existingIds.size}`);
console.log(`Config → englishOnly:${ENGLISH_ONLY}, pmKeywords count:${PM_KEYWORDS.length}`);

const newJobs = pmJobs.filter(item => {
  const jobId = String(item.json.job_id || '').trim();
  return jobId.length > 3 && !existingIds.has(jobId) && !item.json._empty;
});

console.log(`✅ ${newJobs.length} new jobs to save`);

if (newJobs.length === 0) return [{ json: { _noNew: true } }];
return newJobs.map(j => ({ json: { ...j.json, _noNew: false } }));

// Extract full description and Easy Apply status from LinkedIn job page HTML
const jobData = $('📦 Process One Job at a Time').first().json;
const html = typeof $input.first().json === 'string' 
  ? $input.first().json 
  : ($input.first().json.data || $input.first().json.body || '');

// Extract description - LinkedIn wraps it in .description__text
let description = '';
const descMatch = html.match(/class="description__text[^"]*"[^>]*>([\s\S]*?)<\/div>\s*<\/section>/) ||
                  html.match(/show-more-less-html__markup[^>]*>([\s\S]*?)<\/div>/) ||
                  html.match(/<section[^>]*description[^>]*>([\s\S]{100,5000})/);
if (descMatch) {
  // Strip HTML tags and normalize whitespace
  description = descMatch[1]
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 5000);
}

// Detect Easy Apply from actual job page (more reliable than search page)
const isEasyApply = /easy.apply/i.test(html) || /applyButton.*easy/i.test(html);

return [{
  json: {
    ...jobData,
    description: description || `${jobData.position} at ${jobData.company} in ${jobData.location}`,
    apply_type: isEasyApply ? 'LinkedIn Easy Apply' : (jobData.apply_type || 'LinkedIn External')
  }
}];

