// Parse OpenAI response and attach to job data
const jobData = $('🔍 Parse Full Description').first().json;
const openAiResponse = $input.first().json;

let extractedData = {
  required_skills: [],
  nice_to_have_skills: [],
  ats_keywords: [],
  experience_years: null,
  job_summary: ''
};

try {
  const content = openAiResponse.choices[0].message.content;
  // Remove markdown code blocks if present
  const cleanJson = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  extractedData = JSON.parse(cleanJson);
} catch(e) {
  console.error('Failed to parse OpenAI response:', e.message);
}

return [{
  json: {
    ...jobData,
    extracted_skills: JSON.stringify(extractedData.required_skills || []),
    ats_keywords: JSON.stringify(extractedData.ats_keywords || []),
    nice_to_have: JSON.stringify(extractedData.nice_to_have_skills || []),
    experience_years: extractedData.experience_years,
    job_summary: extractedData.job_summary || ''
  }
}];

// Compare job required skills against my skills and find gaps
const jobData = $('📝 Parse Extracted Skills').first().json;
const mySkillsData = $('📊 Get My Skills Sheet').all();

// Build my skills set (lowercase for comparison)
const mySkills = new Set(
  mySkillsData
    .map(item => (item.json.skill || item.json.Skill || '').toLowerCase().trim())
    .filter(s => s.length > 0)
);

// Parse required skills from job
let requiredSkills = [];
let atsKeywords = [];
try {
  requiredSkills = JSON.parse(jobData.extracted_skills || '[]');
  atsKeywords = JSON.parse(jobData.ats_keywords || '[]');
} catch(e) {}

// Find skills I don't have
const missingSkills = requiredSkills.filter(skill => {
  const skillLower = skill.toLowerCase();
  // Check if any of my skills partially match
  return !Array.from(mySkills).some(mySkill => 
    mySkill.includes(skillLower) || skillLower.includes(mySkill)
  );
});

// Find missing ATS keywords
const missingKeywords = atsKeywords.filter(kw => {
  const kwLower = kw.toLowerCase();
  return !Array.from(mySkills).some(mySkill => mySkill.includes(kwLower) || kwLower.includes(mySkill));
});

console.log(`Job: ${jobData.position} @ ${jobData.company}`);
console.log(`Required skills: ${requiredSkills.length}, Missing: ${missingSkills.length}`);

return [{
  json: {
    ...jobData,
    missing_skills: missingSkills.join(', '),
    missing_keywords: missingKeywords.join(', '),
    needs_resume_update: missingSkills.length > 0 || missingKeywords.length > 0,
    skill_match_score: requiredSkills.length > 0 
      ? Math.round(((requiredSkills.length - missingSkills.length) / requiredSkills.length) * 100) 
      : 100
  }
}];

