// Combine all data for application
const jobData = $('🔀 Merge Resume Paths').first().json;
const coverLetterResponse = $input.first().json;
const coverLetter = coverLetterResponse.choices[0].message.content;

// Use the apply_type from the fetched job page (more accurate than search result)
const isEasyApply = (jobData.apply_type || '').includes('Easy Apply');

return [{
  json: {
    ...jobData,
    cover_letter: coverLetter,
    is_easy_apply: isEasyApply,
    ready_to_apply: true,
    application_timestamp: new Date().toISOString()
  }
}];

// Set status for successfully submitted Easy Apply
const job = $('📋 Prepare Application Data').first().json;
const apifyResult = $input.first().json;

return [{
  json: {
    ...job,
    new_status: 'Applied',
    application_id: apifyResult.id || apifyResult.data?.id || 'auto_applied',
    applied_date: new Date().toISOString().split('T')[0],
    notes: `Easy Apply submitted via Apify. Cover letter generated. Skill match: ${job.skill_match_score}%`,
    cover_letter_generated: 'Yes',
    resume_optimized: job.resume_was_updated ? 'Yes' : 'No'
  }
}];

// Set status for jobs requiring manual/direct application
const job = $('📋 Prepare Application Data').first().json;

return [{
  json: {
    ...job,
    new_status: 'Manual Apply Required',
    application_id: '',
    applied_date: '',
    notes: `External apply needed. Cover letter ready. Apply at: ${job.job_url}. Skill match: ${job.skill_match_score}%. Missing skills: ${job.missing_skills}`,
    cover_letter_generated: 'Yes',
    resume_optimized: job.resume_was_updated ? 'Yes' : 'No'
  }
}];

// Generate a status report of all applied jobs
const jobs = $input.all();

const byStatus = {};
for (const item of jobs) {
  const status = item.json.status || 'Unknown';
  if (!byStatus[status]) byStatus[status] = [];
  byStatus[status].push(item.json);
}

const totalApplied = jobs.length;
const needsFollowUp = jobs.filter(j => {
  const appliedDate = new Date(j.json.applied_date || 0);
  const daysSince = (Date.now() - appliedDate.getTime()) / (1000 * 60 * 60 * 24);
  return daysSince >= 7 && j.json.status === 'Applied';
});

return [{
  json: {
    total_applied: totalApplied,
    needs_followup_count: needsFollowUp.length,
    needs_followup: needsFollowUp.map(j => j.json),
    all_jobs: jobs.map(j => j.json),
    report_date: new Date().toISOString().split('T')[0],
    summary_by_status: byStatus
  }
}];
